import{_ as e,o,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"How Aerosol is different","description":"High-level comparison with typical disk cleaners, OS storage tools, and how Aerosol’s file recovery mode fits in.","frontmatter":{"title":"How Aerosol is different","description":"High-level comparison with typical disk cleaners, OS storage tools, and how Aerosol’s file recovery mode fits in."},"headers":[],"relativePath":"compare.md","filePath":"compare.md","lastUpdated":1775592403000}'),d={name:"compare.md"};function a(i,t,n,l,c,p){return o(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="how-aerosol-is-different" tabindex="-1">How Aerosol is different <a class="header-anchor" href="#how-aerosol-is-different" aria-label="Permalink to &quot;How Aerosol is different&quot;">​</a></h1><p>This is a high-level, honest comparison for shoppers. Products change over time — always read each vendor’s own docs and licenses. Aerosol is a young open-source project; maturity and polish will differ from paid suites.</p><table tabindex="0"><thead><tr><th>Topic</th><th>Aerosol</th><th>Typical “optimizer” suites</th><th>OS storage settings</th></tr></thead><tbody><tr><td>Source &amp; auditability</td><td><strong>Open source</strong> — rules and UI are inspectable</td><td>Usually closed source</td><td>N/A (part of OS)</td></tr><tr><td>Pricing model</td><td><strong>Free</strong>; you build or download binaries</td><td>Often subscription or paid upgrades</td><td>Included with OS</td></tr><tr><td>Where data goes</td><td><strong>Local scans</strong>; no Aerosol account required</td><td>Varies; some products phone home</td><td>Local</td></tr><tr><td>Risk transparency</td><td><strong>Safe / review</strong> grouping + dry run</td><td>Often one-click “clean” with less detail</td><td>Limited to what the OS exposes</td></tr><tr><td>Developer / power-user clutter</td><td><strong>Caches, tooling, plugins</strong></td><td>May focus on consumer junk files</td><td>Rarely specialized for dev stacks</td></tr><tr><td>File recovery / rescue</td><td><strong>Read-only folder scans</strong>, previews, copy-out to another path (see <a href="/blog/file-recovery-mode">blog</a>)</td><td>Some suites bundle separate “undelete” tools (often paid); scope varies</td><td>OS tools rarely match this workflow in one place</td></tr><tr><td>Undo / safety</td><td><strong>Trash option</strong> + explicit selection; recovery never writes to source</td><td>Varies; backups still recommended</td><td>Depends on feature</td></tr><tr><td>Maturity</td><td><strong>Early</strong>; expect rough edges</td><td>Often years of QA and support</td><td>Production OS feature</td></tr></tbody></table><p>Mentions of other products are for comparison only; trademarks belong to their owners. BleachBit, CCleaner, CleanMyMac, and similar tools each have different scopes — use the one that matches your threat model and comfort with closed-source maintenance utilities.</p>',4)])])}const f=e(d,[["render",a]]);export{u as __pageData,f as default};
